insert into song_detail_lighting (song_id, detail) values ('dgSleW', '{"lyrics_raw": "[Verse 1]\nSince we''re feeling so anaesthetised\nIn our comfort zone\nReminds me of the second time\nThat I followed you home\nWe''re running out of alibis\nOn the second of May\nReminds me of the summertime\nOn this winter''s day\n\n[Chorus]\nSee you at the bitter end\nSee you at the bitter end\n\n\n\n\n[Verse 2]\nEvery step we take that''s synchronized\nEvery broken bone\nReminds me of the second time\nThat I followed you home\nYou shower me with lullabies\nAs you''re walking away\nReminds me that it''s killing time\nOn this fateful day\n\n[Chorus]\nSee you at the bitter end\nSee you at the bitter end\nSee you at the bitter end\nSee you at the bitter end\n\n[Outro]\n(From the time we intercepted)\n(Feels a lot like suicide)\n(Slow and sad, grown inside us)\nSee you at the bitter end (Arouse and see you''re mine)\n(Love has seen your run-around)\n(Who wanna seek you now?)\n(I want a peace, I''d whine out)\nSee you at the bitter end\n(Love''s reached his side)\n(Grab this gentleness inside)\n(Heard a cry six feet down)\nSee you at the bitter end (In six weeks'' time the mess you left will end", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('F71u8Z', '{"lyrics_raw": "Drip, drip, drip, drip, drip\nDrip, drip, drip, drip, drip\nDrip, drip, drip, drip, drip\nDrip, drip, drip, drip\n\nI shouldn''t laugh but I know I''m a failure in your eyes\nI know it''s daft but I guess that I know it deep inside\nIt feels like we''re ready to crack these days, you and I\nWhen it''s just the two of us, only the two of us, I could die\n\nYou left my heart like an abandoned car\nOld and worn out, no use at all\nBut I used to be free\n\nWe''re gonna separate ourselves tonight\nWe''re always running scared but holding knives\nBut there''s a black chandelier\nIt''s casting shadows and lies\n\nDrip, drip, drip, drip\n\nI''ll sit in silence for the rest of my life if you''d like\nDressing our wounds with industrial gloves made of wire\nFeel it penetrating the skin, we begin to relax\nWhen it''s just the two of us, and a cute little cup of cyanide\n\nYou left my heart like an abandoned car\nOld and worn out, no use at all\nBut I used to be free\n\nWe''re gonna separate ourselves tonight\nWe''re always running scared but holding knives\nBut there''s a black chandelier\nIt''s casting shadows and lies\nWe''re gonna separate ourselves tonight\nWe''re always running scared but holding knives\nBut there''s a black chandelier\n\nYou left my heart like an abandoned car\nOld and worn out, no use at all\nBut I used to be free\n\nWe''re gonna separate ourselves tonight\nWe''re always running scared but holding knives\nBut there''s a black chandelier\nIt''s casting shadows and lies\nWe''re gonna separate ourselves tonight\nWe''re always running scared but holding knives\nBut there''s a black chandelier\n", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('uoloAE', '{"qlc_id": 92, "lyrics_raw": "\nI would say I''m sorry if I thought that it would change your mind\nBut I know that this time if have said too much been too unkind\nI would break down at your feet and beg forgiveness plead with you\nBut I know that it''s no use ''cause now there''s nothing I can do\n\nI try to laugh about it\nCover it all up with lies\nI try to laugh about it\nHiding the tears in my eyes\n\n''Cause boys don''t cry\nBoys don''t cry\n\nI would tell you that I love you if I thought that you would stay\nBut I know that it''s too late ''cause you''ve already gone away\n\nMisjudged your limits\nPushed you too far\nTook you for granted\nI thought that you needed me more, more, more, more\n\nI would do most anything to get you back by my side\nBut I''ll just keep on laughing\nHiding the tears in my eyes\n\n''Cause boys don''t cry\nBoys don''t cry", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('HwfJ9X', '{"qlc_id": 93, "audio_ref": "audio/Chelsea Dagger/Chelsea Dagger - Full Song.mp3", "audio_ref_name": "Chelsea Dagger - Full Song.mp3", "lyrics_raw": "[Intro]\nOh!\n\n[Refrain]\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\n\n[Verse 1]\nWell, you must be a girl with shoes like that\nShe said, \"You know me well\"\nI seen you and little Steven and Joanna\n''Round the back of my hotel, oh yeah\nSomeone said you was asking after me\nBut I know you best as a blagger\nI said, \"Tell me your name, is it sweet?\"\nShe said, \"My boy, it''s Dagger\", oh yeah\n(Woo!)\n\n[Chorus]\nI was good, she was hot, stealin'' everything she got\nI was bold, she was over the worst of it\nGave me gear; thank you, dear, bring your sister over here\nLet her dance with me just for the hell of it\n\n[Refrain]\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\nDo-do-do, do-do-do, do-do-do-do-do-do-do\n\n[Verse 2]\nWell, you must be a boy with bones like that\nShe said, \"You got me wrong\"\nI would''ve sold them to you if I could''ve\nJust to have kept the last of my clothes on, oh yeah\nCall me up, take me down with you when you go\nI could be your regular belle\nAnd I shall dance for little Steven and Joanna\n''Round the back of my hotel, oh yeah\n(Woo!)\n\n[Chorus]\nI was good, she was hot, stealin'' everything she got\nI was bold, she was over the worst of it\nGave me gear; thank you, dear, bring your sister over here\nLet her dance with me just for the hell of it\n\n[Instrumental Break]\n\n[Bridge]\nChelsea, Chelsea, I believe\nThat when you''re dancing slowly, sucking your sleeve\nThe boys get lonely after you leave\nIt''s one for the Dagger and another for the one you believe\nChelsea, I believe\nThat when you''re dancing slowly, sucking your sleeve\nThe boys get lonely after you leave\nIt''s one for the Dagger, another for the one you believe\n\n[Outro]\n(Do-do-do, do-do-do, do-do-do-do-do-do-do) One you believe\n(Do-do-do, do-do-do, do-do-do-do-do) Oh, no, no, no, no\n(Do-do-do, do-do-do, do-do-do-do-do-do-do)\n(Do-do-do, do-do-do, do-do-do-do-do-do-do)\n(Do-do-do, do-do-do, do-do-do-do-do-do-do)\n(Do-do-do, do-do-do, do-do-do-do-do) Hey, hey, hey!\n(Do-do-do, do-do-do, do-do-do-do-do-do-do)\n(Do-do-do, do-do-do, do-do-do-do-do-do-do)\n", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('Lnql7n', '{"qlc_id": 176, "audio_ref": "audio/Creep/Creep - Full Song.mp3", "audio_ref_name": "Creep - Full Song.mp3", "lyrics_raw": "[Verse 1]\nWhen you were here before\nCouldn''t look you in the eye\nYou''re just like an angel\nYour skin makes me cry\nYou float like a feather\nIn a beautiful world\nI wish I was special\nYou''re so fuckin'' special\n\n[Chorus]\nBut I''m a creep\nI''m a weirdo\nWhat the hell am I doin'' here?\nI don''t belong here\n\n[Verse 2]\nI don''t care if it hurts\nI wanna have control\nI want a perfect body\nI want a perfect soul\nI want you to notice\nWhen I''m not around\nYou''re so fuckin'' special\nI wish I was special\n\n[Chorus]\nBut I''m a creep\nI''m a weirdo\nWhat the hell am I doin'' here?\nI don''t belong here\nOh-oh, oh-oh\n\n[Bridge]\nShe''s runnin'' out the door\nShe''s runnin'' out\nShe run, run, run, run\nRun\n\n[Verse 3]\nWhatever makes you happy\nWhatever you want\nYou''re so fuckin'' special\nI wish I was special\n\n[Chorus]\nBut I''m a creep\nI''m a weirdo\nWhat the hell am I doin'' here?\nI don''t belong here\nI don''t belong here\n", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
