insert into song_detail_lighting (song_id, detail) values ('9G8cU7', '{"qlc_id": 94, "audio_ref": "audio/Down In The Past/Down In The Past - Full Song.mp3", "audio_ref_name": "Down In The Past - Full Song.mp3", "lyrics_raw": "[Intro]Yeah!\n\n[Verse 1]\nWell, I don''t wanna hang around with you\nI''ve got my motor, baby, and I''m gonna see you through\nYou think I wanna be alone with you\nIt doesn''t matter, baby, ''cause you overreacted too\n\n[Pre-Chorus]\nBut since you''re down there, where will I just be?\nI''m getting fine, girl\nDressing up for stormy weather\n[Chorus]\nSo touch me\nDown in the past\nWhere my mother will last\nAnd it''s true that I''m in for a punch and a blast\nYeah, down in the past\nWhere my mother will last\nAnd she will make sure that you remember\nYeah!\n\n[Verse 2]\nWell, I don''t wanna slide away with you\nI''ve got ten little soldiers pointing at you\nHoney, you just left me for a new one\nIt doesn''t matter baby cause your hair is ugly too\n\n[Pre-Chorus]\nBut since you''re down there, where will I just be\nI''m getting fine, girl\nDressing up for stormy weather\n\n[Chorus]\nSo touch me\nDown in the past\nWhere my mother will last\nAnd it''s true that I''m in for a punch and a blast\nYeah, down in the past\nWhere my mother will last\nAnd she will make sure that you remember\nYeah, yeah!", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('QeOWYg', '{"lyrics_raw": "[Verse 1]\nWords like violence break the silence\nCome crashing in into my little world\nPainful to me, pierce right through me\nCan''t you understand? Oh, my little girl\n\n[Chorus]\nAll I ever wanted\nAll I ever needed is here in my arms\nWords are very unnecessary\nThey can only do harm\n[Instrumental Break]\n\n[Verse 2]\nVows are spoken to be broken\nFeelings are intense, words are trivial\nPleasures remain, so does the pain\nWords are meaningless and forgettable\n\n[Chorus]\nAll I ever wanted\nAll I ever needed is here in my arms\nWords are very unnecessary\nThey can only do harm\n\n[Instrumental Break]\n\n[Chorus]\nAll I ever wanted\nAll I ever needed is here in my arms\nWords are very unnecessary\nThey can only do harm\nAll I ever wanted\nAll I ever needed is here in my arms\nWords are very unnecessary\nThey can only do harm\n\n[Instrumental Break]\n\n[Outro]\nEnjoy the silence", "tms": {"manual_done": ["bar_markers", "templates_set", "parts_identified"], "user_tasks": [], "manual_undone": []}, "total_bars": 92, "audio_ref": "audio/Enjoy The Silence/Enjoy The Silence - Full Song.mp3", "audio_ref_name": "Enjoy the silence - Template  - zyDkjm.mp3", "split_markers": {"markers": [{"time": 0.7676875000000027}, {"time": 2.9676875000000056}, {"time": 5.205080758426954}, {"time": 7.4744140917602895}, {"time": 9.807747425093618}, {"time": 12.08774742509362}, {"time": 14.303747425093627}, {"time": 16.60774742509363}, {"time": 18.83708075842696}, {"time": 21.125080758426957}, {"time": 23.40508075842696}, {"time": 25.60774742509363}, {"time": 27.93841409176029}, {"time": 30.17041409176029}, {"time": 32.44241409176029}, {"time": 34.73841409176028}, {"time": 36.98908075842696}, {"time": 39.22108075842696}, {"time": 41.47441409176029}, {"time": 43.72241409176028}, {"time": 46.03708075842696}, {"time": 48.32508075842694}, {"time": 50.52508075842696}, {"time": 52.72508075842695}, {"time": 5