insert into song_detail_lighting (song_id, detail) values ('EfmiXn', '{"qlc_id": 95, "audio_ref": "audio/Every You Every Me/Every You Every Me - Full Song.mp3", "audio_ref_name": "Every You Every Me - Full Song.mp3", "lyrics_raw": "Sucker love is heaven sent. You pucker up, our passion''s spent. My hearts a tart, your body''s rent. My body''s broken, yours is spent. Carve your name into my arm. Instead of stressed, I lie here charmed. Cuz there''s nothing else to do, Every me and every you. Sucker love, a box I choose. No other box I choose to use. Another love I would abuse, No circumstances could excuse. In the shape of things to come. Too much poison come undone. Cuz there''s nothing else to do, Every me and every you. Every me and every you, Every Me...he Sucker love is known to swing. Prone to cling and waste these things. Pucker up for heavens sake. There''s never been so much at stake. I serve my head up on a plate. It''s only comfort, calling late. Cuz there''s nothing else to do, Every me and every you. Every me and every you, Every Me...he Every me and every you, Every Me...he Like the naked leads the blind. I know I''m selfish, I''m unkind. Sucker love I always find, Someone to bruise and leave behind. All alone in space and time. There''s nothing here but what here''s here''s mine. Something borrowed, something blue. Every me and every you. Every me and every you, Every Me...he Every me and every you, Every Me...he (x4)", "tms": {"manual_done": ["bar_markers", "parts_identified", "templates_set"], "user_tasks": [{"id": "ut_1775672800235_xmfy", "cat": "lyrics", "label": "Lyrics korrekt in die richtigen Takte verschieben", "done": false}], "manual_undone": []}, "total_bars": 117, "split_markers": {"markers": [{"time": 6.752808988764045}, {"time": 8.339232209737801}, {"time": 9.931232209737843}, {"time": 11.504565543071166}, {"time": 13.149898876404492}, {"time": 14.720565543071174}, {"time": 16.37123220973784}, {"time": 17.981898876404486}, {"time": 19.587