insert into song_detail_lighting (song_id, detail) values ('gRbHPO', '{"lyrics_raw": "[Intro]Cut my life into pieces, this is my last resort\nSuffocation, no breathing\nDon''t give a fuck if I cut my arm bleeding\nThis is my last resort\n\n[Verse 1]\nCut my life into pieces\nI''ve reached my last resort\nSuffocation, no breathing\nDon''t give a fuck if I cut my arm bleeding\nDo you even care if I die bleeding?\nWould it be wrong, would it be right?\nIf I took my life tonight? Chances are that I might\nMutilation out of sight\nAnd I''m contemplatin'' suicide\n[Chorus]\n''Cause I''m losin'' my sight, losin'' my mind\nWish somebody would tell me I''m fine\nLosin'' my sight, losin'' my mind\nWish somebody would tell me I''m fine\n\n[Verse 2]\nI never realized I was spread too thin\n''Til it was too late and I was empty within\nHungry, feeding on chaos and livin'' in sin\nDownward spiral, where do I begin?\nIt all started when I lost my mother\nNo love for myself, and no love for another\nSearchin'' to find a love upon a higher level\nFindin'' nothin'' but questions and devils\n\n[Chorus]\n''Cause I''m losin'' my sight, losin'' my mind\nWish somebody would tell me I''m fine\nLosin'' my sight, losin'' my mind\nWish somebody would tell me I''m fine\n\n[Bridge]\nNothing''s alright, nothing is fine\nI''m runnin'' and I''m cryin''\nI''m cryin'', I''m cryin'', I''m cryin''\nI''m cryin''\nI can''t go on living this way", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
