insert into song_detail_lighting (song_id, detail) values ('pdWrqc', '{"qlc_id": 99, "audio_ref": "audio/Narcotic/Narcotic - Full Song.mp3", "audio_ref_name": "Narcotic - Full Song.mp3", "lyrics_raw": "[Verse 1]So you face it with a smile\nThere is no need to cry\nFor a trifle''s more than this\nWill you still recall my name\nAnd the month it all began?\nWill you release me with a kiss?\nHave I tried to draw the veil?\nIf I have, how could I fail?\nDid I fear the consequence?\n[Pre-Chorus]\nDazed by careless words\nCozy in my mind\n\n[Chorus]\nI don''t mind, I think so\nI will let you go\nI don''t mind, I think so\nI will let you go\n\n[Verse 2]\nNow you shaped that liquid wax\nFit it out with crater cracks\nSweet devotion, my delight\nOh, you''re such a pretty one\nAnd the naked thrills of flesh and skin\nWould tease me through the night\nNow, I hate to leave you bare\nIf you need me, I''ll be there\nDon''t you ever let me down\n\n[Pre-Chorus]\nDazed by careless words\nCozy in my mind\n\n[Chorus]\nI don''t mind, I think so\nI will let you go\nI don''t mind, I think so\nI will let you go", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('Pol09a', '{"qlc_id": 100, "lyrics_raw": "[Verse 1]You are the sun\nYou are the only one\nMy heart is blue\nMy heart is blue for you\n\n[Chorus]\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen, yeah\nBe my, be my, be my little rock ''n'' roll queen\n[Verse 2]\nYou are the sun\nYou are the only one\nYou are so cool\nYou are so rock ''n'' roll\n\n[Chorus]\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen\n\n[Verse 2]\nYou are the sun\nYou are the only one\nYou are so cool\nYou are so rock ''n'' roll\n\n[Chorus]\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen\nBe my, be my, be my little rock ''n'' roll queen, yeah\nBe my, be my, be my little rock ''n'' roll queen", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('hR5CDW', '{"qlc_id": 101, "audio_ref": "audio/Run/Run - Full Song.mp3", "audio_ref_name": "Run - Full Song.mp3", "lyrics_raw": "[Verse 1]\nI''ll sing it one last time for you\nThen we really have to go\nYou''ve been the only thing that''s right\nIn all I''ve done\n\n[Verse 2]\nAnd I can barely look at you\nBut every single time I do\nI know we''ll make it anywhere\nAway from here\n\n\n\n\n[Chorus 1]\nLight up, light up\nAs if you have a choice\nEven if you cannot hear my voice\nI''ll be right beside you, dear\nLouder, louder\nAnd we''ll run for our lives\nI can hardly speak, I understand\nWhy you can''t raise your voice to say\n\n[Verse 3]\nTo think I might not see those eyes\nMakes it so hard not to cry\nAnd as we say our long goodbye\nI nearly do\n\n[Chorus 1]\nLight up, light up\nAs if you have a choice\nEven if you cannot hear my voice\nI''ll be right beside you, dear\nLouder, louder\nAnd we''ll run for our lives\nI can hardly speak, I understand\nWhy you can''t raise your voice to say\n\n[Chorus 2]\nSlower, slower\nWe don''t have time for that\nAll I want''s to find an easy way\nTo get out of our little heads\nHave heart, my dear\nWe''re bound to be afraid\nEven if it''s just for a few days\nMaking up for all this mess\n\n[Instrumental Break]\n\n[Outro]\nLight up, light up\nAs if you have a choice\nEven if you cannot hear my voice\nI''ll be right beside you, dear", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('lVbPMR', '{"qlc_id": 102, "audio_ref": "audio/Self Esteem/Self Esteem - Full Song.mp3", "audio_ref_name": "Self Esteem - Full Song.mp3", "lyrics_raw": "[Intro]La, la, la-la-la\nLa, la, la-la-la\n\n[Verse 1]\nI wrote her off for the tenth time today\nAnd practiced all the things I would say\nBut she came over, I lost my nerve\nI took her back and made her dessert\n\n[Pre-Chorus]\nOh, I know I''m being used\nThat''s okay, man, ''cause I like the abuse\nI know she''s playing with me\nThat''s okay ''cause I''ve got no self-esteem\n[Chorus]\nOh, way, oh yeah, yeah\nOh yeah, yeah\nOh yeah, yeah\nOh yeah, yeah\n\n[Verse 2]\nWe make plans to go out at night\nI wait ''til two, then I turn out the light\nThis rejection''s got me so low\nIf she keeps it up, I just might tell her so\n\n[Chorus]\nOh, way, oh yeah, yeah\nOh yeah, yeah\nOh yeah, yeah\nOh yeah, yeah\n\n[Post-Chorus]\nWhen she''s saying, oh, that she wants only me\nThen I wonder why she sleeps with my friends\nWhen she''s saying, oh, that I''m like a disease\nThen I wonder how much more I can spend\nWell, I guess I should stick up for myself\nBut I really think it''s better this way\nThe more you suffer\nThe more it shows you really care\nRight? Yeah", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('Wa1bpl', '{"qlc_id": 104, "audio_ref": "audio/Sex on Fire/Sex on Fire - Full Song.mp3", "audio_ref_name": "Sex on Fire - Full Song.mp3", "lyrics_raw": "[Verse 1]\nLay where you''re layin''\nDon''t make a sound\nI know they''re watchin''\nThey''re watchin''\nAll the commotion\nThe kiddie-like play\nIt has people talkin''\nTalkin''\n\n[Chorus]\nYou\nYour sex is on fire\n[Verse 2]\nThe dark of the alley\nThe breakin'' of day\nHead while I''m drivin''\nI''m drivin''\nSoft lips are open\nThem knuckles are pale\nFeels like you''re dyin''\nYou''re dyin''\n\n[Chorus]\nYou\nYour sex is on fire\nConsumed\nWith what''s to transpire\n\n[Verse 3]\nHot as a fever\nRattlin'' bones\nI could just taste it\nTaste it\nIf it''s not forever\nIf it''s just tonight\nOh, we''re still the greatest\nThe greatest, the greatest\n\n[Chorus]\nYou\nYour sex is on fire\nYou\nYour sex is on fire, ah\nConsumed\nWith what''s to transpire\nAnd you\nYour sex is on fire\nConsume\nWith what''s to transpire", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('RED66i', '{"qlc_id": 171, "audio_ref": "audio/She Hates Me/She Hates Me - Full Song.mp3", "audio_ref_name": "She Hates Me - Full Song.mp3", "lyrics_raw": "[Verse 1]\nMet a girl, thought she was grand\nFell in love, found out first hand\nWent well for a week or two\nThen it all came unglued\n\n[Pre-Chorus]\nIn a trap, trip I can''t grip\nNever thought I''d be the one who''d slip\nThen I started to realize\nI was living one big lie\n\n[Chorus]\nShe fucking hates me\nTrust, she fucking hates me\nLa-la-la-love\nI tried too hard\nAnd she tore my feelings like I had none\nAnd ripped them away\n\n[Verse 2]\nShe was queen for about an hour\nAfter that, shit got sour\nShe took all I ever had\nNo sign of guilt\nNo feeling of bad, no\n\n[Pre-Chorus]\nIn a trap, trip I can''t grip\nNever thought I''d be the one who''d slip\nThen I started to realize\nI was living one big lie\n\n[Chorus]\nShe fucking hates me\nTrust, she fucking hates me\nLa-la-la-love\nI tried too hard\nAnd she tore my feelings like I had none\nAnd ripped them away\n\n[Bridge]\nThat''s my story, as you see\nLearned my lesson and so did she\nNow it''s over and I''m glad\nCause I''m a fool for all I''ve said\n\n[Chorus]\nShe fucking hates me\nTrust, she fucking hates me\nLa-la-la-love\nI tried too hard\nAnd she tore my feelings like I had none\nAnd ripped them away\n\n[Outro]\nLa-la-la-la-la-la-la-la-la-love\nTrust\nLa-la-la-la-la-la-la-la-la-love\nTrust\nLa-la-la-la-la-la-la-la-la-love\nAnd she tore my feelings like I had none (Trust)\nLa-la-la-la-la-la-la-la-la-love (Trust)\nShe fucking hates me\n\nI never got any action\nHahahahahaha\nShe fucking hates me\nLet''s do the, uh, reverse thing\nI never got any action anyway\n\n", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('rNOnoq', '{"audio_ref": "audio/Should I Stay Or Should I Go/Should I Stay Or Should I Go - Full Song.mp3", "audio_ref_name": "Should I Stay Or Should I Go - Full Song.mp3", "lyrics_raw": "[Intro]Woo (Yo)\nHola\n\n[Verse 1]\nDarling, you got to let me know\nShould I stay, or should I go?\nIf you say that you are mine\nI''ll be here till the end of time\nSo you got to let me know\nShould I stay, or should I go?\nIt''s always tease, tease, tease\nYou''re happy when I''m on my knees\nOne day it''s fine, and next it''s black\nSo if you want me off your back\nWell, come on and let me know\nShould I stay, or should I go?\n[Chorus]\nShould I stay, or should I go now?\nShould I stay, or should I go now?\nIf I go, there will be trouble\nAnd if I stay, it will be double\nSo come on and let me know\n\n[Verse 2]\nThis indecision''s bugging me (Esta indecisión me molesta)\nIf you don''t want me, set me free (Si no me quieres, líbrame)\nExactly whom I''m supposed to be (Dígame qué tengo ser)\nDon''t you know which clothes even fit me? (¿Sabes qué ropa me queda?)\nCome on and let me know (Ahora me tienes que decir)\nShould I cool it, or should I blow? (¿Me debo ir o quedarme?)\n\n[Bridge]\nSplit\n(Doble, ¿me frio o lo soplo?)\n(Esperda; no)\n\n[Chorus]\nShould I stay, or should I go now? (¿Yo me enfrío o lo soplo?)\nShould I stay, or should I go now? (¿Yo me enfrío o lo soplo?)\nIf I go, there will be trouble (Si me voy va a haber peligro)\nAnd if I stay, it will be double (Si me quedo será el doble)\nSo ya gotta let me know (Ahora me tienes que decir)\nShould I cool it, or should I blow? (Tengo frío por los ojos)\nShould I stay, or should I go now? (Tengo frío por los ojos)\nIf I go, there will be trouble (Si me voy va haber peligro)\nAnd if I stay, it will be double (Si me quedo será el doble)\nSo ya gotta let me know (Me tienes que decir)\nShould I stay, or should I go?", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('srQxlI', '{"qlc_id": 106, "audio_ref": "audio/Song 2/Song 2 - Full Song.mp3", "audio_ref_name": "Song 2 - Full Song.mp3", "lyrics_raw": "[Intro]\nWoo-hoo\nWoo-hoo\nWoo-hoo\nWoo-hoo\n\n[Verse 1]\nI got my head checked\nBy a jumbo jet\nIt wasn''t easy\nBut nothing is, no\n[Chorus]\n(Woo-hoo) When I feel heavy metal\n(Woo-hoo) And I''m pins and I''m needles\n(Woo-hoo) Well, I lie and I''m easy\nAll of the time, but I''m never sure why I need you\nPleased to meet you\n\n[Verse 2]\nI got my head done\nWhen I was young\nIt''s not my problem\nIt''s not my problem\n\n[Chorus]\n(Woo-hoo) When I feel heavy metal\n(Woo-hoo) And I''m pins and I''m needles\n(Woo-hoo) Well, I lie and I''m easy\nAll of the time, but I''m never sure why I need you\nPleased to meet you\n\n[Outro]\nYeah-yeah\nYeah-yeah\nYeah-yeah\nOh, yeah", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('JHUGOo', '{"qlc_id": 172, "audio_ref": "audio/Space Lord/Space Lord - Full Song.mp3", "audio_ref_name": "Space Lord - Full Song.mp3", "lyrics_raw": "[Verse 1]\nI''ve been stuffed in your pocket for the last hundred days\nWhen I don''t get my bath I take it out on the slaves\nSo grease up your baby for the ball on the hill\nAnd polish them rockets now, and swallow those pills\nAnd sing\n\n[Chorus]\nOh, Space Lord Mother Mother\nHuh, uh-huh, mm\n[Verse 2]\nThere''s a car in the field now in a column of flame\nWith two doors to choose but only one bears your name\nYou''ve been drinking my blood, well, I''ve been licking your wounds\nWell, I''ll shave off the pitch now in the scope of your tune\nYou''ll sing\n\n[Chorus]\nOh, Space Lord Mother Mother\nHuh, yeah\n\n[Verse 3]\nI left my throne a million miles away\nI drink from your tit, I sing your blues every day\nNow give me the strength to split the world in two, yeah\nI ate all the rest and now I''ve gotta eat you\nWell, I sing\n\n[Verse 4]\nBuilt in my nightmares and using my name\nYou''re strobing my cortex and you know I''m insane\nI''m squeezed out in a hump drive and drownin'' in love\nEncompass them all to a position above\nAnd sing\n\n[Chorus]\nOh, Space Lord Mother Mother\nYeah, ah yeah, hey, hey, hey, hey\n[Verse 5]\nI left my throne a million miles away\nI drink from your tit, I sing your blues every day\nNow give me the strength to split the world in two, yeah\nI ate all the rest and now I''ve gotta eat you\nWell, I sing\n\n[Chorus]\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\n\n[Bridge]\nI lost my soul when I fell to earth\nMy planets called me to the void of my birth\nThe time has come for me to kill this game\nNow open wide and say my name\n\n[Outro]\nSpace Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother\nWay, Space Lord Mother Mother", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('SaUgTX', '{"lyrics_raw": "\n​\n[Verse 1]You can tell by the way she walks that she''s my girl\nYou can tell by the way she talks, she rules the world\nYou can see in her eyes that no one is her chain\nShe''s my girl, my supergirl\n\n[Chorus]\nAnd then she''d say, \"It''s okay\"\n\"I got lost on the way, but I''m a supergirl\"\nAnd supergirls don''t cry\nAnd then she''d say, \"It''s alright\"\n\"I got home late last night, but I''m a supergirl\"\nAnd supergirls just fly\n[Verse 2]\nAnd then she''d say that nothing can go wrong\nWhen you''re in love, what can go wrong?\nThen she''d laugh the night time into day\nPushing her fear further long\n\n[Chorus]\nAnd then she''d say, \"It''s okay\"\n\"I got lost on the way, but I''m a supergirl\"\nAnd supergirls don''t cry\nAnd then she''d say, \"It''s alright\"\n\"I got home late last night, but I''m a supergirl\"\nAnd supergirls just fly\n\n[Verse 3]\nAnd then she''d shout down the line\nTell me she''s got no more time\n''Cause she''s a supergirl\nAnd supergirls don''t hide\nAnd then she''d scream in my face\nTell me to leave, leave this place\n''Cause she''s a supergirl\nAnd supergirls just fly\n\n[Outro]\nYes, she''s a supergirl, a supergirl\nShe''s sowin'' seeds, she''s burnin'' trees\nShe''s sowin'' seeds, she''s burnin'' trees\nYes, she''s a supergirl, a supergirl\nA supergirl, my supergirl", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('SQfqPy', '{"qlc_id": 107, "audio_ref": "audio/Teenage Dirtbag/Teenage Dirtbag - Full Song.mp3", "audio_ref_name": "Teenage Dirtbag - Full Song.mp3", "lyrics_raw": "[Verse 1]Her name is Noelle, I have a dream about her\nShe rings my bell, I got gym class in half an hour\nOh, how she rocks in Keds and tube socks\nBut she doesn''t know who I am, and she doesn''t give a damn about me\n\n[Chorus]\n''Cause I''m just a teenage dirtbag, baby\nYeah, I''m just a teenage dirtbag, baby\nListen to Iron Maiden, baby, with me, ooh\n[Verse 2]\nHer boyfriend''s a dick and he brings a gun to school\nAnd he''d simply kick my ass if he knew the truth\nHe lives on my block, and he drives an IROC\nBut he doesn''t know who I am, and he doesn''t give a damn about me\n\n[Chorus]\n''Cause I''m just a teenage dirtbag, baby\nYeah, I''m just a teenage dirtbag, baby\nListen to Iron Maiden, baby, with me, ooh\n\n[Refrain]\nOh, yeah, dirtbag\nNo, she doesn''t know what she''s missin''\nOh, yeah, dirtbag\nNo, she doesn''t know what she''s missin''\n\n[Verse 3]\nMan, I feel like mold, it''s prom night and I am lonely\nLo and behold, she''s walkin'' over to me\nThis must be fake, my lip starts to shake\nHow does she know who I am? And why does she give a damn about me?\n\n[Bridge]\nI''ve got two tickets to Iron Maiden, baby\nCome with me Friday, don''t say maybe\nI''m just a teenage dirtbag, baby, like you, ooh", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('SlpEnr', '{"qlc_id": 56, "audio_ref": "audio/Tension/Tension - Full Song.mp3", "audio_ref_name": "Tension - Full Song.mp3", "lyrics_raw": "What’s that sound ringing in your head?\nThe angels share what she last said\nThey’re so high\nIt’s alright\nRest your head, to sleep on this\nGot a shot on sight, but all have missed \nI’m so high\nIt’s alright\n\nBut I’ll follow where you go\nDown every street you know\nCause you’ve got the tension\nI’m just pulling tight on every thing\nBelieve it when I say\nLeave it for another rainy day \nCause you’ve got the tension\nI’m just pulling tight\n\nRest your eyes, your little weary head \nWith all that’s gone, it’s all been said\nIn good time\nWhat’s that noise running round your bones?\nIt’s all you’ve got when left alone\nIt’s alright \nIn good time\n\nBut I’ll follow where you go\nDown every street you know\nCause you’ve got the tension\nI’m just pulling tight on every thing\nBelieve it when I say\nLeave it for another rainy day \nCause you’ve got the tension\nI’m just pulling tight\n\nGot the message safe and sound\nIt’s noise to my ears all around inside\nTo look inside\nI’ve made my bed on another lie\nTo try again, to look outside this time\nTo look outside\n\nBut I’ll follow where you go\nDown every street you know\nCause you’ve got the tension\nI’m just pulling tight on every thing\nBelieve it when I say\nLeave it for another rainy day \nCause you’ve got the tension\nI’m just pulling tight", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('Ja3p3E', '{"qlc_id": 108, "audio_ref": "audio/The Boys Of Summer/The Boys Of Summer - Full Song.mp3", "audio_ref_name": "The Boys Of Summer - Full Song.mp3", "lyrics_raw": "[Verse 1]Nobody on the road, nobody on the beach\nI feel it in the air, the summer''s out of reach\nEmpty lake, empty streets, the sun goes down alone\nI''m drivin'' by your house though I know you''re not at home\n\n[Chorus]\nI can see you, your brown skin shinin'' in the sun\nYou got your hair combed back and your sunglasses on, baby\nAnd I can tell you my love for you will still be strong\nAfter the boys of summer have gone\n[Verse 2]\nI never will forget those nights, I wonder if it was a dream\nRemember how you made me crazy? (Crazy) Remember how I made you scream?\nNow I don''t understand what happened to our love\nBut baby, when I get you back, I''m gonna show you what I''m made of\n\n[Chorus]\nI can see you, your brown skin shinin'' in the sun\nI see you walkin'' real slow and you''re smilin'' at everyone\nBut I can tell you my love for you will still be strong\nAfter the boys of summer have gone\n\n[Guitar Solo]\n\n[Verse 3]\nOut on the road today, I saw a Black Flag sticker on a Cadillac\nA little voice inside my head said, \"Don''t look back. You can never look back.\"\nI thought I knew what love was, what did I know?\nThose days are gone forever, I should just let them go, but\n\n[Chorus]\nI can see you, your brown skin shinin'' in the sun\nYou got that top pulled down and that radio on, baby\nNow I can tell you my love for you will still be strong\nAfter the boys of summer have gone\nI can see you, your brown skin shinin'' in the sun\nYou got that hair slicked back and those wayfarers on, baby\nI can tell you my love for you will still be strong\nAfter the boys of summer have gone", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('fwA4K7', '{"qlc_id": 73, "audio_ref": "audio/The Middle/The Middle - Full Song.mp3", "audio_ref_name": "The Middle - Full Song.mp3", "lyrics_raw": "[Verse 1]Hey, don''t write yourself off yet\nIt''s only in your head, you feel left out or looked down on\nJust try your best, try everything you can\nAnd don''t you worry what they tell themselves when you''re away\n\n[Chorus]\nIt just takes some time\nLittle girl, you''re in the middle of the ride\nEverything, everything will be just fine\nEverything, everything will be alright, all right\n[Verse 2]\nHey, you know they''re all the same\nYou know you''re doin'' better on your own (On your own), so don''t buy in\nLive right now, yeah, just be yourself\nIt doesn''t matter if it''s good enough (Good enough) for someone else\n\n[Chorus]\nIt just takes some time\nLittle girl, you''re in the middle of the ride\nEverything, everything will be just fine\nEverything, everything will be all right, all right\nIt just takes some time\nLittle girl, you''re in the middle of the ride\nEverything, everything will be just fine\nEverything, everything will be all right, all right\n\n[Guitar Solo]\nWoo!\n\n[Verse 3]\nHey, don''t write yourself off yet\nIt''s only in your head, you feel left out (Feel left out) or looked down on\nJust do your best (Just do your best), do everything you can (Do everything you can)\nAnd don''t you worry what their bitter hearts (Bitter hearts) are gonna say\n\n[Chorus]\nIt just takes some time\nLittle girl, you''re in the middle of the ride\nEverything, everything will be just fine\nEverything, everything will be all right, all right\nIt just takes some time\nLittle girl, you''re in the middle of the ride\nEverything, everything will be just fine\nEverything, everything will be all right", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('LjFWZO', '{"qlc_id": 173, "audio_ref": "audio/The Pretender/The Pretender - Full Song.mp3", "audio_ref_name": "The Pretender - Full Song.mp3", "lyrics_raw": "[Intro]\nKeep you in the dark, you know they all pretend\nKeep you in the dark and so it all began\n\n[Verse 1]\nSend in your skeletons\nSing as their bones go marchin'' in again\nThe need you buried deep\nThe secrets that you keep are ever ready\nAre you ready?\nI''m finished makin'' sense\nDone pleading ignorance, that whole defense\nSpinning infinity, boy\nThe wheel is spinnin'' me, it''s never ending, never ending\nSame old story\n[Chorus]\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say I will never surrender?\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say that I''ll never surrender?\n\n[Verse 2]\nIn time or so I''m told\nI''m just another soul for sale, oh well\nThe page is out of print\nWe are not permanent, we''re temporary, temporary\nSame old story\n\n[Chorus]\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say I will never surrender?\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say I will never surrender? Oh\n[Bridge]\nI''m the voice inside your head\nYou refuse to hear\nI''m the face that you have to face\nMirrorin'' your stare\nI''m what''s left, I''m what''s right\nI''m the enemy\nI''m the hand that''ll take you down\nBring you to your knees\nSo who are you?\nYeah, who are you?\nYeah, who are you?\nYeah, who are you?\n(Keep you in the dark, you know they all pretend)\n\n[Chorus]\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say I will never surrender?\nWhat if I say I''m not like the others?\nWhat if I say I''m not just another one of your plays?\nYou''re the pretender\nWhat if I say I will never surrender?\n\n[Outro]\nWhat if I say I''m not like the others? (Keep you in the dark)\nWhat if I say I''m not just another one of your plays? (You know they all)\nYou''re the pretender (Pretend)\nWhat if I say I will never surrender?\nWhat if I say I''m not like the others? (Keep you in the dark)\nWhat if I say I''m not just another one of your plays? (You know they all)\nYou''re the pretender (Pretend)\nWhat if I say I will never surrender?\nSo who are you?\nYeah, who are you?\nYeah, who are you?", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('DYL6l8', '{"qlc_id": 109, "lyrics_raw": "[Verse 1]I''m not a perfect person\nThere''s many things I wish I didn''t do\nBut I continue learning\nI never meant to do those things to you\nAnd so I have to say before I go\nThat I just want you to know\n\n[Chorus]\nI''ve found a reason for me\nTo change who I used to be\nA reason to start over new\nAnd the reason is you\n[Verse 2]\nI''m sorry that I hurt you\nIt''s something I must live with every day\nAnd all the pain I put you through\nI wish that I could take it all away\nAnd be the one who catches all your tears\nThat''s why I need you to hear\n\n[Chorus]\nI''ve found a reason for me\nTo change who I used to be\nA reason to start over new\nAnd the reason is you\n\n[Post-Chorus]\nAnd the reason is you\nAnd the reason is you\nAnd the reason is you\n\n[Break]\nI''m not a perfect person\nI never meant to do those things to you\nAnd so I have to say before I go\nThat I just want you to know\n\n[Chorus]\nI''ve found a reason for me\nTo change who I used to be\nA reason to start over new\nAnd the reason is you\nI''ve found a reason to show\nA side of me you didn''t know\nA reason for all that I do\nAnd the reason is you", "tms": {"manual_done": [], "user_tasks": [{"id": "ut_1779254679357_l44n", "cat": "live", "label": "noch mal proben", "done": false}], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('2c4rCI', '{"qlc_id": 110, "audio_ref": "audio/Today/Today - Full Song.mp3", "audio_ref_name": "Today - Full Song.mp3", "lyrics_raw": "Today is the greatest\nDay I''ve ever known\nCan''t live for tomorrow\nTomorrow''s much too long\nI''ll burn my eyes out\nBefore I get out\nI wanted more\nThan life could ever grant me\nBored by the chore\nOf saving face\nToday is the greatest\nDay I''ve ever known\nCan''t wait for tomorrow\nI might not have that long\nI''ll tear my heart out\nBefore I get out\nPink ribbon scars\nThat never forget\nI tried so hard\nTo cleanse these regrets\nMy angel wings\nWere bruised and restrained\nMy belly stings\nToday is\nToday is\nToday is\nThe greatest day\nI want to turn you on\nI want to turn you on\nI want to turn you on\nI want to turn you\nToday is the greatest\nToday is the greatest day\nToday is the greatest day\nThat I have ever really known", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('GXCFTH', '{"qlc_id": 111, "audio_ref": "audio/Torn/Torn - Full Song.mp3", "audio_ref_name": "Torn - Full Song.mp3", "lyrics_raw": "[Verse 1]I thought I saw a girl brought to life\nShe was warm, she came around and she was dignified\nShe showed me what it was to cry\nI couldn''t be the man that you adored\nYou don''t seem to know, or seem to care what my heart is for\nI don''t know you anymore\n\n[Pre-Chorus]\nThere''s nothing where you used to lie\nThe conversation has run dry\nThat''s what''s going on\n[Chorus]\nNothing''s right, I''m torn\nI''m all out of faith\nThis is how I feel\nI''m cold and I am shamed\nLying naked on the floor\nIllusion never changed\nInto something real\nI''m wide awake and I can see\nThe perfect sky is torn\nYou''re a little late, I''m already torn\n\n[Verse 2]\nSo I guess the fortune teller''s right\nI should have seen just what was there\nAnd not some holy light\nYou crawled beneath my veins\n\n[Pre-Chorus]\nAnd now I don''t care, I had no luck\nI don''t miss it all that much\nThere''s just so many things\n\n[Chorus]\nThat I can touch, I''m torn\nI''m all out of faith\nThis is how I feel\nI''m cold and I am shamed\nLying naked on the floor\nIllusion never changed\nInto something real\nI''m wide awake and I can see\nThe perfect sky is torn\nYou''re a little late, I''m already torn\nTorn", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('Dp8xoz', '{"qlc_id": 72, "audio_ref": "audio/Valerie/Valerie - Full Song.mp3", "audio_ref_name": "Valerie - Full Song.mp3", "lyrics_raw": "[Verse 1]Well, sometimes, I go out by myself\nAnd I look across the water\nAnd I think of all the things, what you do\nAnd in my head, I make a picture\n\n[Pre-Chorus]\n''Cause since I''ve come on home\nWell, my body''s been a mess\nAnd I''ve missed your ginger hair\nAnd the way you like to dress\nWon''t you come on over?\nStop makin'' a fool out of me\n[Chorus]\nWhy don''t you come on over, Valerie?\nValerie\n\n[Verse 2]\nDid you have to go to jail?\nPut your house on up for sale?\nDid you get a good lawyer?\nI hope you didn''t catch a tan\nI hope you find the right man\nWho''ll fix it for you\nAre you shoppin'' anywhere?\nChanged the colour of your hair?\nAre you busy?\nAnd did you have to pay the fine\nYou were dodging all the time?\nAre you still dizzy? Yeah\n\n[Pre-Chorus]\n''Cause since I''ve come on home\nWell, my body''s been a mess\nAnd I''ve missed your ginger hair\nAnd the way you like to dress\nWon''t you come on over?\nStop makin'' a fool out of me", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('zf3UaB', '{"qlc_id": 112, "audio_ref": "audio/Word Up/Word Up - Full Song.mp3", "audio_ref_name": "Word Up - Full Song.mp3", "lyrics_raw": "You pretty ladies around the worldGot a weird thing to show you\nSo tell all the boys and girls\nTell your brother, your sister, and your mama too\nCuz we''re about to go down\nAnd you know just what to do\nWave your hands in the air like you don''t care\nGilde by the people as they start to look and stare\nDo your dance, do your dance, do your dance quick mama\nCome on baby tell me what''s the word\nWord up everybody says\nWhen you hear the call you''ve got to get it underway\nWord up it''s the code word\nNo matter where you say it, you know that you''ll be heard\n\nNow all you sucker DJ''s who think you''re fly\nThere''s got to be a reason and we know the reason why\nWhy you put on those airs and you act real cool\nBut you got to realise that you''re acting like fools\nIf there''s music we can use it\nWe''re free to dance\nWe don''t have the for physichological romance\nNo romance, no romance, no romance for me mama\nCome on baby tell me what''s the word\n\nWord up everybody says\nWhen you hear the call you''ve got to get it underway\n\nDial \"L\" for Love (x4)\n\nW-O-R-D up (x4)\n\nAll you sucker DJ''s who think you''re fly\nThere''s got to be a reason and we know the reason why\nWhy you put on those airs and you act real cool\nBut you got to realise that you''re acting like fools", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
insert into song_detail_lighting (song_id, detail) values ('sowvsF', '{"qlc_id": 24, "audio_ref": "audio/Yellow/Yellow - Full Song.mp3", "audio_ref_name": "Yellow - Full Song.mp3", "lyrics_raw": "\n​\n[Verse 1: Chris Martin]\nLook at the stars\nLook how they shine for you\nAnd everything you do\nYeah, they were all yellow\nI came along\nI wrote a song for you\nAnd all the things you do\nAnd it was called \"Yellow\"\nSo then I took my turn\nOh, what a thing to have done\nAnd it was all yellow\n[Chorus: Chris Martin, Guy Berryman, Jonny Buckland & Will Champion]\n(Ah) Your skin, oh, yeah, your skin and bones\n(Ooh) Turn into something beautiful\n(Ah) And you know, you know I love you so\nYou know I love you so\n\n[Verse 2: Chris Martin]\nI swam across\nI jumped across for you\nOh, what a thing to do\n''Cause you were all yellow\nI drew a line\nI drew a line for you\nOh, what a thing to do\nAnd it was all yellow\n\n[Chorus: Chris Martin, Jonny Buckland & Will Champion]\n(Ah) And your skin, oh, yeah, your skin and bones\n(Ooh) Turn into something beautiful\n(Ah) And you know, for you, I''d bleed myself dry\nFor you, I''d bleed myself dry\n\n[Bridge: Chris Martin]\nIt''s true\nLook how they shine for you\nLook how they shine for you\nLook how they shine for\nLook how they shine for you\nLook how they shine for you\nLook how they shine", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
