insert into song_detail_lighting (song_id, detail) values ('I8M2A8', '{"audio_ref": "audio/Seven Nation Army + Sweet Dreams/Seven Nation Army + Sweet Dreams - Full Song.mp3", "audio_ref_name": "Seven Nation Army + Sweet Dreams - Full Song.mp3", "lyrics_raw": "[Verse 1]I''m gonna fight ''em off\nA seven-nation army couldn''t hold me back\nThey''re gonna rip it off\nTakin'' their time right behind my back\nAnd I''m talkin'' to myself at night because I can''t forget\nBack and forth through my mind, behind a cigarette\nAnd the message comin'' from my eyes says, \"Leave it alone\"\n\n[Instrumental Break]\n[Verse 2]\nDon''t wanna hear about it\nEvery single one''s got a story to tell\nEveryone knows about it\nFrom the Queen of England to the Hounds of Hell\nAnd if I catch it comin'' back my way, I''m gonna serve it to you\nAnd that ain''t what you want to hear, but that''s what I''ll do\nAnd the feelin'' comin'' from my bones says, \"Find a home\"\n\n[Guitar Solo]\n\n[Verse 3]\nI''m goin'' to Wichita\nFar from this opera forevermore\nI''m gonna work the straw\nMake the sweat drip out of every pore\nAnd I''m bleedin'' and I''m bleedin'' and I''m bleedin'' right before the Lord\nAll the words are gonna bleed from me and I will think no more\nAnd the stains comin'' from my blood tell me, \"Go back home\"\n\n\n​\n[Chorus]Sweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\n\n[Verse]\nSome of them want to use you\nSome of them want to get used by you\nSome of them want to abuse you\nSome of them want to be abused\n[Chorus]\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\n\n[Bridge]\nHold your head up\nKeep your head up (Movin'' on)\nHold your head up (Movin'' on)\nKeep your head up (Movin'' on)\nHold your head up (Movin'' on)\nKeep your head up (Movin'' on)\nHold your head up (Movin'' on)\nKeep your head up\n\n[Keyboard Solo]\n\n[Verse]\nSome of them want to use you\nSome of them want to get used by you\nSome of them want to abuse you\nSome of them want to be abused\n\n[Chorus]\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\nSweet dreams are made of this\nWho am I to disagree?\nI travel the world and the seven seas\nEverybody''s looking for something\nSweet dreams are made of this", "tms": {"manual_done": [], "user_tasks": [], "manual_undone": []}, "total_bars": 0}'::jsonb) on conflict (song_id) do nothing;
